var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"스캐빈저 놈들이 다이브하는 걸 막지 못했다고?","JPN":"スカベンジャーのダイブを止められなかった？","ENG":"You couldn't stop the Scavengers from Diving?","TWN":"你說無法阻止那些清道夫躍入？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래서, 지금 놈들을 놓쳤다는 말인가?","JPN":"それで、今奴らを逃しただと？","ENG":"Are you saying you lost them?","TWN":"意思是被那些傢伙給逃掉了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"연구선을 통째로 인양해 가는데 놓치다니! 하나같이 무능해 빠져서는!","JPN":"研究船を丸ごと盗んでいったのに逃しただと！？　どいつもこいつも無能ばかりだな！","ENG":"They were hauling a research ship behind them, and you lost them! So incompetent, every single one of you!","TWN":"整艘研究船被人劫走，竟然連一個人都抓不到！一群沒用的東西！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이러니 용병 나부랭이들을 믿고 일을 맡길 수가 없지……!","JPN":"これだから傭兵なんかに安心して仕事を任せられない……！","ENG":"This is why I can't trust mercenaries.","TWN":"我就說不能放心把事情交代給傭兵的嘛……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……그래도 당신네 회사는 그나마 말귀를 알아듣는 모양이군.","JPN":"……だが、この会社はまだマシなようだな。","ENG":"... At least your company is not as bad as the others.","TWN":"……不過你們公司還算聽得懂人話。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"다른 놈들이 잔챙이들한테 정신이 팔린 동안 당신네 직원들은 스캐빈저를 쫓았다지?","JPN":"他の連中が雑魚に気を取られている間、そちらの社員はスカベンジャーを追ったと聞いた。","ENG":"While the others were distracted by small fry, your employees followed the Scavengers.","TWN":"在其他人掉入調虎離山的陷阱時，你們的員工反而是去追清道夫對吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하지만 과정 따위는 중요하지 않아. 사업엔 결과가 전부지.","JPN":"しかし過程なぞ重要ではない。事業は結果が全てだ。","ENG":"But in the business world, what you do doesn't matter; what you get does.","TWN":"不過這也不是重點，公司在乎的只有結果。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 맡긴 의뢰는 해적 놈들이 훔쳐 간 연구선을 되찾아오는 거요.","JPN":"私が任せた依頼は、海賊が盗んだ研究船を取り戻すことだ。","ENG":"I hired you to retrieve my research ship from the pirates.","TWN":"我的委託是要找回被海盜劫走的研究船。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"다시 말해, 연구선을 회수해 와야 보수를 받을 수 있다는 뜻이지.","JPN":"つまり、研究船を回収しないと報酬はもらえないという意味になる。","ENG":"In other words, you're not going to get paid until you do.","TWN":"意思就是，沒有研究船就沒有酬勞！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"방금 내가 한 말, 잘 기억해 두시오.","JPN":"今の言葉を、くれぐれも忘れないように。","ENG":"You'd better remember that.","TWN":"這一點請你們牢牢記住！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 이 영감탱이야! 잘했다고 한마디 하면 어디 덧나?!","JPN":"はあ？　おい、ジジイ！　よくやったとかご苦労様の一言も言えないのか？","ENG":"Hey, you old coot! Is it so difficult to say, \\"Good job?\\"","TWN":"這個臭老頭！誇獎我們一下會少塊肉嗎？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유, 유진아. 이건 단방향 수신 메시지야. 그렇게 소리쳐도 저쪽에는 안 들려.","JPN":"シ、シロコ。これは単方向受信メッセージだよ。そんなに怒っても向こうには聞こえないよ。","ENG":"E-Eujin. This is an inbound simplex message. He can't hear you even if you yell.","TWN":"劉…劉珍，這是單工通訊，你喊破喉嚨對方也聽不到的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그렇지만 조금 심하네……. 해적들하고 싸우느라 죽거나 다친 사람도 많을 텐데…….","JPN":"それにしてもちょっとひどいね……海賊と戦って怪我したり命を落とした人もいるはずなのに……","ENG":"But he's being really harsh. Lots of people got hurt and even died fighting the pirates.","TWN":"雖然他講話真的很難聽……應該有很多人因為和海盜交手，而受傷或死掉吧……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그만큼 연구선에 실려 있는 데이터가 중요하단 뜻이겠지.","JPN":"それぐらい、研究船にあるデータが重要ってことだろうね。","ENG":"He cares so much about the data in the research ship.","TWN":"這就表示研究船裡的資料非常重要！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아니면, 애초에 일이 끝나면 살려 둘 생각이 없었다거나…….","JPN":"あるいは、そもそも仕事が終わった後は生かしておくつもりがなかったとか……","ENG":"Or he has no intention of letting us live after this.","TWN":"或者，從一開始他就打算，等事情結束後就要滅口……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 방금 뭐라고 한 거야?","JPN":"ん？　今なんて言ったか？","ENG":"What? What did you just say?","TWN":"什麼？你剛說什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아무것도 아냐. 그보다 특이사항 보고해야지.","JPN":"なんでもない。それより特異事項を報告しないと。","ENG":"Nothing. Anyway, we'd better report to the Boss and Vice President.","TWN":"沒有啦！還是先報告特殊事項吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};